class Standard {
    List<String> ignore;
    List<dynamic> envs;

    Standard({
        required this.ignore,
        required this.envs,
    });

    factory Standard.fromJson(Map<String, dynamic> json) => Standard(
        ignore: List<String>.from(json["ignore"].map((x) => x)),
        envs: List<dynamic>.from(json["envs"].map((x) => x)),
    );

    Map<String, dynamic> toJson() => {
        "ignore": List<dynamic>.from(ignore.map((x) => x)),
        "envs": List<dynamic>.from(envs.map((x) => x)),
    };
}
